The `debounce` function is a higher-order function that delays the execution of a given function by a specified amount of time, ensuring it only runs after a certain period of inactivity.

```javascript
function debounce(fn, wait) {
  let timeout;
  return function(...args) {
    clearTimeout(timeout);
    timeout = setTimeout(() => fn(...args), wait);
  };
}

// Example usage:
const debouncedLog = debounce(console.log, 500);
debouncedLog('Hello'); // This will be logged after 500ms
debouncedLog('World'); // This will override the previous log and be logged after 500ms
```
